# --- Business Logic Layer ---

class FinancialBusinessLogic:
    """Encapsulates all business logic for financial operations."""

    @staticmethod
    def validate_account(account_id):
        if account_id not in ACCOUNTS_DB:
            return False, f"Account '{account_id}' not found."
        return True, "Account valid."

    @staticmethod
    def validate_active_account(account_id):
        valid, msg = FinancialBusinessLogic.validate_account(account_id)
        if not valid:
            return False, msg
        if not ACCOUNTS_DB[account_id]["is_active"]:
            return False, f"Account '{account_id}' is inactive/suspended."
        return True, "Account active and valid."

    @staticmethod
    def get_balance(account_id):
        valid, msg = FinancialBusinessLogic.validate_account(account_id)
        if not valid:
            return None, msg
        account = ACCOUNTS_DB[account_id]
        return {
            "account_id": account_id,
            "balance": account["balance"],
            "currency": account["currency"],
        }, "Success"

    @staticmethod
    def get_account_info(account_id):
        valid, msg = FinancialBusinessLogic.validate_account(account_id)
        if not valid:
            return None, msg
        account = ACCOUNTS_DB[account_id]
        return dict(account), "Success"

    @staticmethod
    def transfer_funds(from_account_id, to_account_id, amount, currency="USD"):
        if amount <= 0:
            return None, "Transfer amount must be positive."

        if from_account_id == to_account_id:
            return None, "Cannot transfer to the same account."

        valid, msg = FinancialBusinessLogic.validate_active_account(from_account_id)
        if not valid:
            return None, f"Source account error: {msg}"

        valid, msg = FinancialBusinessLogic.validate_active_account(to_account_id)
        if not valid:
            return None, f"Destination account error: {msg}"

        from_account = ACCOUNTS_DB[from_account_id]
        to_account = ACCOUNTS_DB[to_account_id]

        if from_account["currency"] != currency or to_account["currency"] != currency:
            return None, "Currency mismatch. Cross-currency transfers not supported."

        if from_account["balance"] < amount:
            return None, f"Insufficient funds. Available: {from_account['balance']} {currency}"

        # Execute transfer
        from_account["balance"] -= amount
        to_account["balance"] += amount

        txn_id = f"TXN{datetime.utcnow().strftime('%Y%m%d%H%M%S')}{len(TRANSACTION_LOG):04d}"
        timestamp = datetime.utcnow()

        TRANSACTION_LOG.append({
            "transaction_id": txn_id,
            "from_account": from_account_id,
            "to_account": to_account_id,
            "amount": amount,
            "currency": currency,
            "timestamp": timestamp,
            "description": f"Transfer from {from_account_id} to {to_account_id}",
        })

        return {
            "transaction_id": txn_id,
            "from_account": from_account_id,
            "to_account": to_account_id,
            "amount": amount,
            "currency": currency,
            "from_new_balance": from_account["balance"],
            "to_new_balance": to_account["balance"],
            "timestamp": timestamp,
        }, "Transfer completed successfully."

    @staticmethod
    def get_transaction_history(account_id, limit=50):
        valid, msg = FinancialBusinessLogic.validate_account(account_id)
        if not valid:
            return None, msg

        txns = [
            t for t in TRANSACTION_LOG
            if t["from_account"] == account_id or t["to_account"] == account_id
        ]
        txns = txns[-limit:]
        return txns, "Success"

    @staticmethod
    def list_all_accounts():
        accounts = list(ACCOUNTS_DB.values())
        return accounts, "Success"


