        """Helper to simulate a SOAP request against the WSGI app."""
        envelope = f"""<?xml version="1.0" encoding="UTF-8"?>
        <soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/"
                       xmlns:fin="urn:financial.services">
            <soap:Header/>
            <soap:Body>
                {soap_body_xml}
            </soap:Body>
        </soap:Envelope>"""

        encoded = envelope.encode("utf-8")

        environ = {
            "REQUEST_METHOD": "POST",
            "CONTENT_TYPE": "text/xml; charset=utf-8",
            "CONTENT_LENGTH": str(len(encoded)),
            "PATH_INFO": "/",
            "SERVER_NAME": "localhost",
            "SERVER_PORT": "8000",
            "HTTP_SOAPACTION": f'"{soap_action}"',
            "wsgi.input": io.BytesIO(encoded),
            "wsgi.errors": io.BytesIO(),
            "wsgi.url_scheme": "http",
        }

        response_body = []
        response_status = [None]
        response_headers = [None]

        def start_response(status, headers):
            response_status[0] = status
            response_headers[0] = headers
            return response_body.append

        result = wsgi_app(environ, start_response)
        response_data = b"".join(result)

        return response_status[0], response_data

